84428497-276a-4cdd-adcd-61d18b5c135c.custom_css:
body {
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%) !important;
    color: #e94560 !important;
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
}

.container, .card, div[style*="background-color"] {
    background: rgba(255, 255, 255, 0.05) !important;
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.1) !important;
    border-radius: 20px !important;
    padding: 20px;
}

input, select, textarea {
    background: rgba(0, 0, 0, 0.3) !important;
    border: 1px solid #e94560 !important;
    border-radius: 12px !important;
    color: #fff !important;
    padding: 10px !important;
    transition: 0.3s;
}

input:focus, textarea:focus {
    box-shadow: 0 0 15px rgba(233, 69, 96, 0.5) !important;
    outline: none;
}
button, .btn-primary, button[type="submit"] {
    background: linear-gradient(90deg, #e94560, #950740) !important;
    border: none !important;
    border-radius: 50px !important;
    text-transform: uppercase;
    letter-spacing: 1px;
    font-weight: bold;
    box-shadow: 0 5px 15px rgba(233, 69, 96, 0.4);
    cursor: pointer;
    transition: 0.4s;
}

/* حركة عند تمرير الماوس فوق الزر */
button:hover {
    transform: scale(1.05);
    box-shadow: 0 8px 20px rgba(233, 69, 96, 0.6);
}

h2, h3, label {
    color: #0f3460 !important; /* لون سماوي غامق أو ذهبي حسب رغبتك */
    text-shadow: 1px 1px 2px rgba(0,0,0,0.5);
}
